"use client";

import { useState, useEffect, useRef } from "react";
import { apiGet } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/components/ui/use-toast";
import { formatCurrency } from "@/lib/utils";
import { Barcode, Printer, Search } from "lucide-react";
import { Checkbox } from "@/components/ui/checkbox";

interface ProductSize {
  size: string;
  stock: number;
}

interface Product {
  id: string;
  name: string;
  sku: string;
  costPrice: number;
  salePrice: number;
  stock: number;
  sizes: ProductSize[];
}

export default function BarcodesPage() {
  const { toast } = useToast();
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedProducts, setSelectedProducts] = useState<Set<string>>(new Set());
  const [search, setSearch] = useState("");
  const printRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchProducts();
    loadJsBarcode();
  }, []);

  const loadJsBarcode = () => {
    if (typeof window !== "undefined" && !(window as any).JsBarcode) {
      const script = document.createElement("script");
      script.src = "https://cdn.jsdelivr.net/npm/jsbarcode@3.11.6/dist/JsBarcode.all.min.js";
      script.async = true;
      document.body.appendChild(script);
    }
  };

  const fetchProducts = async () => {
    try {
      const data = await apiGet("/api/products");
      if (Array.isArray(data)) {
        setProducts(data);
      }
    } catch (error) {
      toast({ title: "Erro ao carregar produtos", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const filteredProducts = products.filter((product) => {
    return product.name.toLowerCase().includes(search.toLowerCase()) ||
      product.sku.toLowerCase().includes(search.toLowerCase());
  });

  const toggleProduct = (productId: string) => {
    const newSelected = new Set(selectedProducts);
    if (newSelected.has(productId)) {
      newSelected.delete(productId);
    } else {
      newSelected.add(productId);
    }
    setSelectedProducts(newSelected);
  };

  const toggleAll = () => {
    if (selectedProducts.size === filteredProducts.length) {
      setSelectedProducts(new Set());
    } else {
      setSelectedProducts(new Set(filteredProducts.map((p) => p.id)));
    }
  };

  const generateBarcodes = () => {
    if (selectedProducts.size === 0) {
      toast({ title: "Selecione pelo menos um produto", variant: "destructive" });
      return;
    }

    const selectedProductsList = products.filter((p) => selectedProducts.has(p.id));
    
    const printWindow = window.open("", "_blank", "width=800,height=600");
    if (!printWindow) {
      toast({ title: "Erro ao abrir janela de impressão", variant: "destructive" });
      return;
    }

    const barcodesHtml = selectedProductsList
      .map((product) => {
        // Generate stock quantity copies of each barcode
        const barcodeItems = Array(product.stock)
          .fill(null)
          .map(
            (_, i) => `
            <div class="barcode-item">
              <div class="product-name">${product.name}</div>
              <svg class="barcode" id="barcode-${product.id}-${i}"></svg>
              <div class="product-price">${formatCurrency(product.salePrice)}</div>
            </div>
          `
          )
          .join("");
        return barcodeItems;
      })
      .join("");

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
      <head>
        <title>Códigos de Barras</title>
        <script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.6/dist/JsBarcode.all.min.js"></script>
        <style>
          * { margin: 0; padding: 0; box-sizing: border-box; }
          body { 
            font-family: Arial, sans-serif;
            padding: 10mm;
          }
          .barcodes-container {
            display: flex;
            flex-wrap: wrap;
            gap: 4.5mm;
            justify-content: flex-start;
          }
          .barcode-item {
            width: 45mm;
            padding: 2.7mm;
            border: 1px dashed #ccc;
            text-align: center;
            page-break-inside: avoid;
          }
          .product-name {
            font-size: 8px;
            font-weight: bold;
            margin-bottom: 1.8mm;
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
          .barcode {
            width: 100%;
            height: auto;
          }
          .product-price {
            font-size: 14px;
            font-weight: bold;
            line-height: 1;
            margin-top: 1.6mm;
          }
          @media print {
            body { padding: 5mm; }
            .barcode-item { border: 1px dashed #999; }
          }
        </style>
      </head>
      <body>
        <div class="barcodes-container">
          ${barcodesHtml}
        </div>
        <script>
          window.onload = function() {
            ${selectedProductsList
              .map((product) =>
                Array(product.stock)
                  .fill(null)
                  .map(
                    (_, i) => `
                    JsBarcode("#barcode-${product.id}-${i}", "${product.sku}", {
                      format: "CODE128",
                      width: 1.35,
                      height: 36,
                      displayValue: false,
                      fontSize: 10,
                      margin: 4
                    });
                  `
                  )
                  .join("")
              )
              .join("")}
            setTimeout(function() {
              window.print();
            }, 500);
          };
        </script>
      </body>
      </html>
    `);
    printWindow.document.close();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Códigos de Barras</h1>
          <p className="text-gray-500">Gere etiquetas com códigos de barras para os produtos</p>
        </div>
        <Button onClick={generateBarcodes} disabled={selectedProducts.size === 0}>
          <Printer className="h-4 w-4 mr-2" />
          Imprimir ({selectedProducts.size})
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Barcode className="h-5 w-5" />
            Selecione os Produtos
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-4 items-end">
            <div className="flex-1 space-y-2">
              <Label>Buscar</Label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                <Input
                  placeholder="Buscar por nome ou SKU..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
          </div>

          {loading ? (
            <p className="text-center py-4">Carregando...</p>
          ) : filteredProducts.length === 0 ? (
            <p className="text-center py-4 text-gray-500">Nenhum produto encontrado</p>
          ) : (
            <div className="border rounded-lg overflow-hidden">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left">
                      <Checkbox
                        checked={selectedProducts.size === filteredProducts.length && filteredProducts.length > 0}
                        onCheckedChange={toggleAll}
                      />
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Produto</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">SKU</th>
                    <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Estoque</th>
                    <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Preço</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {filteredProducts.map((product) => (
                    <tr
                      key={product.id}
                      className={`hover:bg-gray-50 cursor-pointer ${
                        selectedProducts.has(product.id) ? "bg-blue-50" : ""
                      }`}
                      onClick={() => toggleProduct(product.id)}
                    >
                      <td className="px-4 py-3">
                        <Checkbox
                          checked={selectedProducts.has(product.id)}
                          onCheckedChange={() => toggleProduct(product.id)}
                        />
                      </td>
                      <td className="px-4 py-3 font-medium">{product.name}</td>
                      <td className="px-4 py-3 text-gray-500 font-mono">{product.sku}</td>
                      <td className="px-4 py-3 text-right">{product.stock}</td>
                      <td className="px-4 py-3 text-right">{formatCurrency(product.salePrice)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useAuth } from "@/contexts/auth-context";
import { apiDelete, apiGet, apiPatch, apiPost } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/components/ui/use-toast";
import { formatCurrency } from "@/lib/utils";
import { Check, Trash2 } from "lucide-react";

type BillStatus = "PENDING" | "PAID";

type Bill = {
  id: string;
  name: string;
  amount: number;
  dueDate: { _seconds: number; _nanoseconds: number } | string;
  status: BillStatus;
  kind: "FIXED" | "ONE_TIME" | "INSTALLMENT";
  groupId?: string;
  installmentNumber?: number;
  installmentsCount?: number;
  paidAt?: { _seconds: number; _nanoseconds: number } | string | null;
  paidMethod?: "DINHEIRO" | "DEBITO" | "CREDITO" | "PIX" | null;
};

type StoreReport = {
  profit: number;
};

function tsToDate(value: Bill["dueDate"]): Date {
  if (typeof value === "string") return new Date(value);
  if (value && typeof value === "object" && "_seconds" in value) {
    return new Date(value._seconds * 1000);
  }
  return new Date(0);
}

function formatDateBR(d: Date) {
  return d.toLocaleDateString("pt-BR");
}

export default function BillsPage() {
  const { userData } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [bills, setBills] = useState<Bill[]>([]);
  const [month, setMonth] = useState(() => new Date().toISOString().slice(0, 7));
  const [status, setStatus] = useState<"all" | "pending" | "paid">("pending");

  const [report, setReport] = useState<StoreReport | null>(null);
  const [reportLoading, setReportLoading] = useState(false);

  const [creating, setCreating] = useState(false);
  const [kind, setKind] = useState<"FIXED" | "ONE_TIME" | "INSTALLMENTS">("ONE_TIME");
  const [name, setName] = useState("");
  const [amount, setAmount] = useState<string>("");
  const [dueDate, setDueDate] = useState<string>(new Date().toISOString().slice(0, 10));
  const [dayOfMonth, setDayOfMonth] = useState<string>("5");
  const [monthsAhead, setMonthsAhead] = useState<string>("12");
  const [firstDueDate, setFirstDueDate] = useState<string>(new Date().toISOString().slice(0, 10));
  const [installmentsCount, setInstallmentsCount] = useState<string>("3");

  const fetchBills = async () => {
    setLoading(true);
    try {
      const data = await apiGet(`/api/bills?month=${encodeURIComponent(month)}&status=${encodeURIComponent(status)}`);
      setBills(Array.isArray(data) ? data : []);
    } catch (error) {
      toast({ title: "Erro ao carregar contas", variant: "destructive" });
      setBills([]);
    } finally {
      setLoading(false);
    }
  };

  const fetchReport = async () => {
    setReportLoading(true);
    try {
      if (!/^\d{4}-\d{2}$/.test(month)) {
        setReport(null);
        return;
      }
      const [y, m] = month.split("-").map((v) => parseInt(v, 10));
      const start = new Date(y, m - 1, 1);
      const end = new Date(y, m, 1);

      const data = await apiGet(
        `/api/reports?startDate=${encodeURIComponent(start.toISOString())}&endDate=${encodeURIComponent(end.toISOString())}`
      );
      setReport({ profit: typeof data?.profit === "number" ? data.profit : 0 });
    } catch (error) {
      setReport(null);
      toast({ title: "Erro ao carregar lucro do mês", variant: "destructive" });
    } finally {
      setReportLoading(false);
    }
  };

  useEffect(() => {
    if (userData?.role === "ADMIN") {
      fetchBills();
      fetchReport();
    }
  }, [month, status, userData?.role]);

  const totals = useMemo(() => {
    const pending = bills.filter((b) => b.status === "PENDING").reduce((s, b) => s + (b.amount || 0), 0);
    const paid = bills.filter((b) => b.status === "PAID").reduce((s, b) => s + (b.amount || 0), 0);
    return { pending, paid };
  }, [bills]);

  const handleMarkPaid = async (billId: string) => {
    const method = prompt("Forma de pagamento (DINHEIRO/DEBITO/CREDITO/PIX):", "DINHEIRO") || "DINHEIRO";
    try {
      await apiPatch(`/api/bills/${billId}`, { action: "mark_paid", method });
      toast({ title: "Conta marcada como paga" });
      fetchBills();
    } catch (error) {
      toast({ title: "Erro ao atualizar conta", variant: "destructive" });
    }
  };

  const handleDelete = async (billId: string) => {
    if (!confirm("Excluir esta conta?")) return;
    try {
      await apiDelete(`/api/bills/${billId}`);
      toast({ title: "Conta excluída" });
      fetchBills();
    } catch (error) {
      toast({ title: "Erro ao excluir conta", variant: "destructive" });
    }
  };

  const handleCreate = async () => {
    const parsed = parseFloat(amount);
    if (!name.trim()) {
      toast({ title: "Informe o nome", variant: "destructive" });
      return;
    }
    if (!Number.isFinite(parsed) || parsed <= 0) {
      toast({ title: "Informe um valor válido", variant: "destructive" });
      return;
    }

    setCreating(true);
    try {
      if (kind === "ONE_TIME") {
        await apiPost("/api/bills", { kind: "ONE_TIME", name: name.trim(), amount: parsed, dueDate });
      } else if (kind === "FIXED") {
        await apiPost("/api/bills", {
          kind: "FIXED",
          name: name.trim(),
          amount: parsed,
          dayOfMonth: parseInt(dayOfMonth, 10),
          monthsAhead: parseInt(monthsAhead, 10),
          startMonth: month,
        });
      } else {
        await apiPost("/api/bills", {
          kind: "INSTALLMENTS",
          name: name.trim(),
          amount: parsed,
          firstDueDate,
          installmentsCount: parseInt(installmentsCount, 10),
          intervalMonths: 1,
        });
      }

      toast({ title: "Conta(s) criada(s)" });
      setName("");
      setAmount("");
      fetchBills();
    } catch (error) {
      toast({ title: "Erro ao criar conta", description: error instanceof Error ? error.message : undefined, variant: "destructive" });
    } finally {
      setCreating(false);
    }
  };

  if (userData?.role !== "ADMIN") {
    return (
      <div className="flex items-center justify-center h-96">
        <p className="text-gray-500">Você não tem permissão para acessar esta página.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-900">Contas</h1>
        <p className="text-gray-500">Controle de contas e despesas da loja</p>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Lucro (mês)</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-[#355444]">
              {reportLoading ? "..." : formatCurrency(report?.profit || 0)}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pendente (mês)</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-red-600">{formatCurrency(totals.pending)}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pago (mês)</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{formatCurrency(totals.paid)}</div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Filtros</CardTitle>
        </CardHeader>
        <CardContent className="flex flex-col gap-4 md:flex-row md:items-end">
          <div className="space-y-2">
            <Label>Mês</Label>
            <Input type="month" value={month} onChange={(e) => setMonth(e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>Status</Label>
            <select
              className="w-full p-2 border rounded-md md:w-48"
              value={status}
              onChange={(e) => setStatus(e.target.value as typeof status)}
            >
              <option value="pending">Pendentes</option>
              <option value="paid">Pagas</option>
              <option value="all">Todas</option>
            </select>
          </div>
          <Button variant="outline" onClick={fetchBills}>
            Atualizar
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Adicionar Conta</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 md:grid-cols-4">
            <div className="space-y-2 md:col-span-2">
              <Label>Nome</Label>
              <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="Ex: Aluguel" />
            </div>
            <div className="space-y-2">
              <Label>Valor</Label>
              <Input value={amount} onChange={(e) => setAmount(e.target.value)} type="number" step="0.01" />
            </div>
            <div className="space-y-2">
              <Label>Tipo</Label>
              <select
                className="w-full p-2 border rounded-md"
                value={kind}
                onChange={(e) => setKind(e.target.value as typeof kind)}
              >
                <option value="ONE_TIME">Avulsa</option>
                <option value="FIXED">Fixa</option>
                <option value="INSTALLMENTS">Parcelada</option>
              </select>
            </div>
          </div>

          {kind === "ONE_TIME" && (
            <div className="space-y-2">
              <Label>Vencimento</Label>
              <Input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} />
            </div>
          )}

          {kind === "FIXED" && (
            <div className="grid gap-4 md:grid-cols-3">
              <div className="space-y-2">
                <Label>Dia do vencimento</Label>
                <Input type="number" min="1" max="31" value={dayOfMonth} onChange={(e) => setDayOfMonth(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Meses à frente</Label>
                <Input type="number" min="1" max="36" value={monthsAhead} onChange={(e) => setMonthsAhead(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Início</Label>
                <Input type="month" value={month} onChange={(e) => setMonth(e.target.value)} />
              </div>
            </div>
          )}

          {kind === "INSTALLMENTS" && (
            <div className="grid gap-4 md:grid-cols-3">
              <div className="space-y-2">
                <Label>1º vencimento</Label>
                <Input type="date" value={firstDueDate} onChange={(e) => setFirstDueDate(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Nº parcelas</Label>
                <Input type="number" min="1" max="60" value={installmentsCount} onChange={(e) => setInstallmentsCount(e.target.value)} />
              </div>
            </div>
          )}

          <div className="flex justify-end">
            <Button onClick={handleCreate} disabled={creating}>
              {creating ? "Salvando..." : "Adicionar"}
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Contas do Mês</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <p className="text-center py-4">Carregando...</p>
          ) : bills.length === 0 ? (
            <p className="text-center py-4 text-gray-500">Nenhuma conta encontrada</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Vencimento</TableHead>
                  <TableHead>Conta</TableHead>
                  <TableHead>Tipo</TableHead>
                  <TableHead className="text-right">Valor</TableHead>
                  <TableHead className="text-right">Status</TableHead>
                  <TableHead className="text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {bills.map((b) => {
                  const d = tsToDate(b.dueDate);
                  const typeLabel =
                    b.kind === "FIXED" ? "Fixa" : b.kind === "ONE_TIME" ? "Avulsa" : b.installmentNumber && b.installmentsCount
                      ? `Parcela ${b.installmentNumber}/${b.installmentsCount}`
                      : "Parcelada";

                  return (
                    <TableRow key={b.id}>
                      <TableCell>{formatDateBR(d)}</TableCell>
                      <TableCell className="font-medium">{b.name}</TableCell>
                      <TableCell>{typeLabel}</TableCell>
                      <TableCell className="text-right font-bold">{formatCurrency(b.amount)}</TableCell>
                      <TableCell className={`text-right font-bold ${b.status === "PAID" ? "text-green-600" : "text-red-600"}`}>
                        {b.status === "PAID" ? "Pago" : "Pendente"}
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex justify-end gap-2">
                          {b.status === "PENDING" && (
                            <Button size="icon" variant="ghost" onClick={() => handleMarkPaid(b.id)} title="Marcar como pago">
                              <Check className="h-4 w-4" />
                            </Button>
                          )}
                          <Button size="icon" variant="ghost" className="text-red-500" onClick={() => handleDelete(b.id)} title="Excluir">
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/contexts/auth-context";
import { apiGet, apiPost, apiPut, apiDelete, apiPatch } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { useToast } from "@/components/ui/use-toast";
import { formatCurrency } from "@/lib/utils";
import { Plus, Pencil, Trash2, Users, CreditCard, Eye, RefreshCw, Printer } from "lucide-react";

interface Order {
  id: string;
  totalAmount: number;
  createdAt: string;
  amountPaid?: number;
  remainingAmount?: number;
  items?: OrderItem[];
}

interface OrderItem {
  id: string;
  productName?: string;
  size?: string;
  quantity: number;
}

interface Client {
  id: string;
  name: string;
  phone?: string;
  email?: string;
  notes?: string;
  balance: number;
  pendingOrders?: Order[];
}

export default function ClientsPage() {
  const { userData } = useAuth();
  const { toast } = useToast();
  const [clients, setClients] = useState<Client[]>([]);
  const [loading, setLoading] = useState(true);
  const [migratingFiado, setMigratingFiado] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [paymentDialogOpen, setPaymentDialogOpen] = useState(false);
  const [payingOrderId, setPayingOrderId] = useState<string | null>(null);
  const [paymentAmount, setPaymentAmount] = useState<string>("");
  const [paymentMethod, setPaymentMethod] = useState<"DINHEIRO" | "DEBITO" | "CREDITO" | "PIX">("DINHEIRO");
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    email: "",
    notes: "",
  });

  const fetchClients = async () => {
    try {
      const data = await apiGet("/api/clients");
      setClients(Array.isArray(data) ? data : []);
    } catch (error) {
      toast({ title: "Erro ao carregar clientes", variant: "destructive" });
      setClients([]);
    } finally {
      setLoading(false);
    }
  };

  const printClientDebtDetails = (client: Client) => {
    const printWindow = window.open("", "_blank", "width=420,height=700");
    if (!printWindow) {
      toast({ title: "Erro ao abrir janela de impressão", variant: "destructive" });
      return;
    }

    const now = new Date();
    const dateStr = now.toLocaleDateString("pt-BR");
    const timeStr = now.toLocaleTimeString("pt-BR");
    const pendingOrders = client.pendingOrders || [];
    const totalPending = pendingOrders.reduce((sum, order) => {
      const remaining = typeof order.remainingAmount === "number" ? order.remainingAmount : order.totalAmount;
      return sum + remaining;
    }, 0);

    const ordersHtml = pendingOrders.length
      ? pendingOrders
          .map((order) => {
            const remaining = typeof order.remainingAmount === "number" ? order.remainingAmount : order.totalAmount;
            const paid = typeof order.amountPaid === "number" ? order.amountPaid : 0;
            const itemsHtml = order.items && order.items.length > 0
              ? order.items
                  .map((item) => `<div class="item-line">${item.quantity}x ${item.productName || "Produto removido"}${item.size ? ` (${item.size})` : ""}</div>`)
                  .join("")
              : '<div class="item-line">Sem itens detalhados</div>';

            return `
              <div class="order-block">
                <div class="row"><span class="label">Pedido:</span><span>#${order.id.slice(-6).toUpperCase()}</span></div>
                <div class="row"><span class="label">Data:</span><span>${new Date(order.createdAt).toLocaleDateString("pt-BR")}</span></div>
                <div class="row"><span class="label">Pago:</span><span>${formatCurrency(paid)}</span></div>
                <div class="row bold"><span class="label">Restante:</span><span>${formatCurrency(remaining)}</span></div>
                <div class="items">${itemsHtml}</div>
              </div>
            `;
          })
          .join("")
      : '<div class="empty">Nenhum pedido pendente.</div>';

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Detalhes</title>
          <style>
            * { margin: 0; padding: 0; box-sizing: border-box; }
            html, body { width: 80mm; max-width: 80mm; }
            body {
              font-family: 'Courier New', Courier, monospace;
              font-size: 11px;
              line-height: 1.3;
              font-weight: 600;
              color: #000;
              padding: 2.5mm 2.5mm 3mm;
              overflow-wrap: anywhere;
              word-break: break-word;
            }
            .center { text-align: center; }
            .title { font-size: 14px; font-weight: bold; margin-bottom: 4px; }
            .divider { margin: 8px 0; border-top: 1px dashed #000; }
            .section { margin: 6px 0; }
            .row { display: flex; justify-content: space-between; gap: 8px; margin: 2px 0; }
            .label { color: #333; }
            .bold { font-weight: bold; }
            .order-block { border: 1px dashed #000; padding: 6px; margin: 6px 0; }
            .items { margin-top: 4px; }
            .item-line { font-size: 10px; margin: 1px 0; }
            .total { font-size: 13px; font-weight: bold; text-align: right; }
            .empty { text-align: center; margin: 8px 0; }
            @media print {
              html, body { width: 80mm !important; max-width: 80mm !important; }
              @page { margin: 0; size: 80mm auto; }
            }
          </style>
        </head>
        <body>
          <div class="center title">DETALHES</div>
          <div class="divider"></div>

          <div class="section">
            <div class="row"><span class="label">Cliente:</span><span>${client.name}</span></div>
            ${client.phone ? `<div class="row"><span class="label">Telefone:</span><span>${client.phone}</span></div>` : ""}
            <div class="row"><span class="label">Emissão:</span><span>${dateStr} ${timeStr}</span></div>
          </div>

          <div class="divider"></div>
          <div class="section">
            <div class="bold">Pedidos Pendentes</div>
            ${ordersHtml}
          </div>

          <div class="divider"></div>
          <div class="total">TOTAL PENDENTE: ${formatCurrency(totalPending)}</div>

          <script>
            window.onload = function() {
              window.print();
              window.onafterprint = function() { window.close(); };
            };
          </script>
        </body>
      </html>
    `);

    printWindow.document.close();
  };

  useEffect(() => {
    fetchClients();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      if (editingClient) {
        await apiPut(`/api/clients/${editingClient.id}`, formData);
        toast({ title: "Cliente atualizado!" });
      } else {
        await apiPost("/api/clients", formData);
        toast({ title: "Cliente criado!" });
      }
      setDialogOpen(false);
      resetForm();
      fetchClients();
    } catch (error) {
      toast({
        title: "Erro",
        description: error instanceof Error ? error.message : "Erro desconhecido",
        variant: "destructive",
      });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Tem certeza que deseja excluir este cliente?")) return;

    try {
      await apiDelete(`/api/clients/${id}`);
      toast({ title: "Cliente excluído!" });
      fetchClients();
    } catch (error) {
      toast({ 
        title: "Erro ao excluir cliente", 
        description: error instanceof Error ? error.message : "Erro desconhecido",
        variant: "destructive" 
      });
    }
  };

  const handleEdit = (client: Client) => {
    setEditingClient(client);
    setFormData({
      name: client.name,
      phone: client.phone || "",
      email: client.email || "",
      notes: client.notes || "",
    });
    setDialogOpen(true);
  };

  const handleViewDetails = async (client: Client) => {
    try {
      const data = await apiGet(`/api/clients/${client.id}`);
      setSelectedClient(data);
      setDetailsOpen(true);
    } catch (error) {
      toast({ title: "Erro ao carregar detalhes", variant: "destructive" });
    }
  };

  const openPayDialog = (order: Order) => {
    setPayingOrderId(order.id);
    const remaining = typeof order.remainingAmount === "number" ? order.remainingAmount : order.totalAmount;
    setPaymentAmount(remaining.toFixed(2));
    setPaymentMethod("DINHEIRO");
    setPaymentDialogOpen(true);
  };

  const handleConfirmPayment = async () => {
    if (!selectedClient || !payingOrderId) return;

    const parsed = parseFloat(paymentAmount);
    if (!Number.isFinite(parsed) || parsed <= 0) {
      toast({ title: "Informe um valor válido", variant: "destructive" });
      return;
    }

    try {
      const updated = await apiPatch(`/api/clients/${selectedClient.id}`, {
        action: "pay_order",
        orderId: payingOrderId,
        amount: parsed,
        method: paymentMethod,
      });
      setSelectedClient({ ...updated, pendingOrders: updated.pendingOrders || [] });
      toast({ title: "Pagamento registrado!" });
      setPaymentDialogOpen(false);
      setPayingOrderId(null);
      fetchClients();
    } catch (error) {
      toast({ title: "Erro ao registrar pagamento", variant: "destructive" });
    }
  };

  const resetForm = () => {
    setEditingClient(null);
    setFormData({
      name: "",
      phone: "",
      email: "",
      notes: "",
    });
  };

  const openNewDialog = () => {
    resetForm();
    setDialogOpen(true);
  };

  const handleMigrateFiado = async () => {
    if (migratingFiado) return;

    try {
      setMigratingFiado(true);

      const dryRun = await apiPost("/api/admin/migrate-fiado", { apply: false, limit: 200 });
      const toUpdate = typeof dryRun?.toUpdate === "number" ? dryRun.toUpdate : 0;

      if (toUpdate <= 0) {
        toast({ title: "Migração FIADO", description: "Nenhum pedido para atualizar." });
        return;
      }

      const ok = confirm(
        `Migração FIADO: ${toUpdate} pedido(s) serão atualizados.\n\nDeseja aplicar agora?`
      );
      if (!ok) return;

      const applied = await apiPost("/api/admin/migrate-fiado", { apply: true, limit: 200 });
      const updated = typeof applied?.updated === "number" ? applied.updated : 0;
      const errors = typeof applied?.errors === "number" ? applied.errors : 0;

      toast({
        title: "Migração FIADO concluída",
        description: `Atualizados: ${updated}. Erros: ${errors}.`,
      });

      if (detailsOpen && selectedClient) {
        const refreshed = await apiGet(`/api/clients/${selectedClient.id}`);
        setSelectedClient(refreshed);
      }
      fetchClients();
    } catch (error) {
      toast({
        title: "Erro na migração FIADO",
        description: error instanceof Error ? error.message : "Erro desconhecido",
        variant: "destructive",
      });
    } finally {
      setMigratingFiado(false);
    }
  };

  // Only ADMIN can access this page
  if (userData?.role === "CASHIER") {
    return (
      <div className="flex items-center justify-center h-96">
        <p className="text-gray-500">Você não tem permissão para acessar esta página.</p>
      </div>
    );
  }

  const totalPending = clients.reduce((sum, c) => sum + c.balance, 0);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Clientes</h1>
          <p className="text-gray-500">Gerencie clientes e pagamentos pendentes</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={handleMigrateFiado} disabled={migratingFiado}>
            <RefreshCw className={`h-4 w-4 mr-2 ${migratingFiado ? "animate-spin" : ""}`} />
            Migrar FIADO
          </Button>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button onClick={openNewDialog}>
                <Plus className="h-4 w-4 mr-2" />
                Novo Cliente
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>
                  {editingClient ? "Editar Cliente" : "Novo Cliente"}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Nome *</Label>
                  <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    required
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="phone">Telefone</Label>
                    <Input
                      id="phone"
                      value={formData.phone}
                      onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="email">Email</Label>
                    <Input
                      id="email"
                      type="email"
                      value={formData.email}
                      onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="notes">Observações</Label>
                  <Textarea
                    id="notes"
                    value={formData.notes}
                    onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                    rows={3}
                  />
                </div>
                <div className="flex gap-2 pt-4">
                  <Button type="button" variant="outline" className="flex-1" onClick={() => setDialogOpen(false)}>
                    Cancelar
                  </Button>
                  <Button type="submit" className="flex-1">
                    {editingClient ? "Salvar" : "Criar"}
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total de Clientes</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{clients.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Pendente</CardTitle>
            <CreditCard className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className={`text-2xl font-bold ${totalPending > 0 ? "text-red-600" : "text-green-600"}`}>
              {formatCurrency(totalPending)}
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Lista de Clientes</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <p className="text-center py-4">Carregando...</p>
          ) : clients.length === 0 ? (
            <p className="text-center py-4 text-gray-500">Nenhum cliente cadastrado</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Nome</TableHead>
                  <TableHead>Telefone</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead className="text-right">Saldo Pendente</TableHead>
                  <TableHead className="text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {clients.map((client) => (
                  <TableRow key={client.id}>
                    <TableCell className="font-medium">{client.name}</TableCell>
                    <TableCell>{client.phone || "-"}</TableCell>
                    <TableCell>{client.email || "-"}</TableCell>
                    <TableCell className={`text-right font-bold ${client.balance > 0 ? "text-red-600" : "text-green-600"}`}>
                      {formatCurrency(client.balance)}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleViewDetails(client)}
                          title="Ver detalhes"
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleEdit(client)}
                          title="Editar"
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleDelete(client.id)}
                          className="text-red-500"
                          title="Excluir"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Client Details Dialog */}
      <Dialog open={detailsOpen} onOpenChange={setDetailsOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Detalhes do Cliente</DialogTitle>
          </DialogHeader>
          {selectedClient && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-sm text-gray-500">Nome</p>
                  <p className="font-medium">{selectedClient.name}</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Saldo Pendente</p>
                  <p className={`font-bold ${selectedClient.balance > 0 ? "text-red-600" : "text-green-600"}`}>
                    {formatCurrency(selectedClient.balance)}
                  </p>
                </div>
                {selectedClient.phone && (
                  <div>
                    <p className="text-sm text-gray-500">Telefone</p>
                    <p className="font-medium">{selectedClient.phone}</p>
                  </div>
                )}
                {selectedClient.email && (
                  <div>
                    <p className="text-sm text-gray-500">Email</p>
                    <p className="font-medium">{selectedClient.email}</p>
                  </div>
                )}
              </div>

              {selectedClient.notes && (
                <div>
                  <p className="text-sm text-gray-500">Observações</p>
                  <p className="font-medium">{selectedClient.notes}</p>
                </div>
              )}

              <div>
                <div className="flex items-center justify-between mb-2">
                  <p className="text-sm font-medium text-gray-700">Pedidos Pendentes</p>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => printClientDebtDetails(selectedClient)}
                  >
                    <Printer className="h-4 w-4 mr-2" />
                    Imprimir 80mm
                  </Button>
                </div>
                {selectedClient.pendingOrders && selectedClient.pendingOrders.length > 0 ? (
                  <div className="space-y-2">
                    {selectedClient.pendingOrders.map((order) => {
                      const remaining = typeof order.remainingAmount === "number" ? order.remainingAmount : order.totalAmount;
                      const paid = typeof order.amountPaid === "number" ? order.amountPaid : 0;
                      return (
                      <div key={order.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                        <div className="space-y-1">
                          <p className="text-sm font-medium">Pedido #{order.id.slice(-6).toUpperCase()}</p>
                          <p className="text-xs text-gray-500">
                            {new Date(order.createdAt).toLocaleDateString("pt-BR")}
                          </p>
                          <p className="text-xs text-gray-600">
                            Pago: {formatCurrency(paid)} | Restante: {formatCurrency(remaining)}
                          </p>
                          {order.items && order.items.length > 0 && (
                            <div className="pt-1">
                              <p className="text-xs font-medium text-gray-700">Itens comprados:</p>
                              <ul className="text-xs text-gray-600 list-disc pl-4 space-y-0.5">
                                {order.items.map((item) => (
                                  <li key={item.id}>
                                    {item.quantity}x {item.productName || "Produto removido"}
                                    {item.size ? ` (${item.size})` : ""}
                                  </li>
                                ))}
                              </ul>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-3">
                          <span className="font-bold text-red-600">{formatCurrency(remaining)}</span>
                          <Button size="sm" onClick={() => openPayDialog(order)}>
                            Receber
                          </Button>
                        </div>
                      </div>
                      );
                    })}
                  </div>
                ) : (
                  <p className="text-gray-500 text-sm">Nenhum pedido pendente</p>
                )}
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      <Dialog open={paymentDialogOpen} onOpenChange={setPaymentDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Registrar Pagamento</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="payAmount">Valor</Label>
              <Input
                id="payAmount"
                type="number"
                step="0.01"
                min="0"
                value={paymentAmount}
                onChange={(e) => setPaymentAmount(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Forma</Label>
              <select
                className="w-full p-2 border rounded-md"
                value={paymentMethod}
                onChange={(e) => setPaymentMethod(e.target.value as typeof paymentMethod)}
              >
                <option value="DINHEIRO">Dinheiro</option>
                <option value="DEBITO">Débito</option>
                <option value="CREDITO">Crédito</option>
                <option value="PIX">PIX</option>
              </select>
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setPaymentDialogOpen(false)}>
                Cancelar
              </Button>
              <Button onClick={handleConfirmPayment}>Confirmar</Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiGet } from "@/lib/api-client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { formatCurrency } from "@/lib/utils";
import { DollarSign, Package, ShoppingCart, TrendingUp } from "lucide-react";
import { useAuth } from "@/contexts/auth-context";

interface DashboardStats {
  totalProducts: number;
  totalOrders: number;
  totalRevenue: number;
  totalProfit: number;
}

interface RecentOrder {
  id: string;
  createdAt: string;
  totalAmount: number;
  itemCount: number;
}

export default function DashboardPage() {
  const { userData } = useAuth();
  const [stats, setStats] = useState<DashboardStats>({
    totalProducts: 0,
    totalOrders: 0,
    totalRevenue: 0,
    totalProfit: 0,
  });
  const [recentOrders, setRecentOrders] = useState<RecentOrder[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        // Fetch products
        const products = await apiGet(`/api/products`);
        
        // Fetch orders
        const orders = await apiGet("/api/orders");
        
        // Fetch reports for revenue/profit
        const report = await apiGet("/api/reports").catch(() => null);
        
        // Calculate totals
        const totalRevenue = report?.revenue || 0;
        const totalProfit = report?.profit || 0;
        
        setStats({
          totalProducts: Array.isArray(products) ? products.length : 0,
          totalOrders: Array.isArray(orders) ? orders.length : 0,
          totalRevenue,
          totalProfit,
        });
        
        // Recent orders
        if (Array.isArray(orders)) {
          setRecentOrders(
            orders.slice(0, 5).map((order: { id: string; createdAt: string; totalAmount: number; items?: unknown[] }) => ({
              id: order.id,
              createdAt: order.createdAt,
              totalAmount: order.totalAmount,
              itemCount: order.items?.length || 0,
            }))
          );
        }
      } catch (error) {
        console.error("Error fetching dashboard data:", error);
      } finally {
        setLoading(false);
      }
    }
    
    if (userData) {
      fetchData();
    }
  }, [userData]);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-500">Visão geral do sistema</p>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Receita Total</CardTitle>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatCurrency(stats.totalRevenue)}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Lucro Total</CardTitle>
            <TrendingUp className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{formatCurrency(stats.totalProfit)}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total de Vendas</CardTitle>
            <ShoppingCart className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.totalOrders}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Produtos</CardTitle>
            <Package className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.totalProducts}</div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Vendas Recentes</CardTitle>
        </CardHeader>
        <CardContent>
          {recentOrders.length === 0 ? (
            <p className="text-gray-500 text-center py-4">Nenhuma venda registrada</p>
          ) : (
            <div className="space-y-4">
              {recentOrders.map((order) => (
