"use client";

import { useState, useEffect } from "react";
import { apiGet } from "@/lib/api-client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useToast } from "@/components/ui/use-toast";
import { formatCurrency, formatDate } from "@/lib/utils";
import { ClipboardList, Eye, Download, Banknote, CreditCard, Smartphone, Printer } from "lucide-react";

interface OrderItem {
  id: string;
  quantity: number;
  size?: string;
  unitPrice: number;
  totalRevenue: number;
  profit: number;
  product?: {
    name: string;
    sku: string;
  };
}

interface StoreSettings {
  storeName: string;
  address: string;
  phone: string;
  cnpj: string;
  footerMessage: string;
  exchangeDays: number;
}

interface PaymentMethod {
  method: "DINHEIRO" | "DEBITO" | "CREDITO" | "PIX";
  amount: number;
}

interface FiadoPayment {
  id: string;
  amount: number;
  method: PaymentMethod["method"];
  createdAt: string;
}

interface Order {
  id: string;
  createdAt: string;
  totalAmount: number;
  payments?: PaymentMethod[];
  items: OrderItem[];
  clientId?: string;
  clientName?: string;
  isPaidLater?: boolean;
  amountPaid?: number;
  remainingAmount?: number;
  paymentHistory?: FiadoPayment[];
  paidAt?: string;
}

export default function SalesPage() {
  const { toast } = useToast();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [storeSettings, setStoreSettings] = useState<StoreSettings>({
    storeName: "Gestão Loja",
    address: "",
    phone: "",
    cnpj: "",
    footerMessage: "Obrigado pela preferência!\nVolte sempre!",
    exchangeDays: 10,
  });

  const periodTotalSold = orders.reduce(
    (sum, o) => sum + (typeof o.totalAmount === "number" ? o.totalAmount : 0),
    0
  );

  const periodFiadoOutstanding = orders.reduce((sum, o) => {
    if (!o.isPaidLater) return sum;
    if (typeof o.remainingAmount === "number") return sum + o.remainingAmount;
    return sum + (o.paidAt ? 0 : (typeof o.totalAmount === "number" ? o.totalAmount : 0));
  }, 0);

  const periodReceived = orders.reduce((sum, o) => {
    const total = typeof o.totalAmount === "number" ? o.totalAmount : 0;
    if (!o.isPaidLater) return sum + total;
    if (typeof o.amountPaid === "number") return sum + o.amountPaid;
    return sum + (o.paidAt ? total : 0);
  }, 0);

  const fetchOrders = async (override?: { startDate?: string; endDate?: string }) => {
    setLoading(true);
    try {
      const effectiveStartDate = override?.startDate ?? startDate;
      const effectiveEndDate = override?.endDate ?? endDate;

      let url = "/api/orders";
      const params = new URLSearchParams();
      if (effectiveStartDate) params.append("startDate", effectiveStartDate);
      if (effectiveEndDate) params.append("endDate", effectiveEndDate);
      if (params.toString()) url += `?${params.toString()}`;

      const data = await apiGet(url);
      const normalizedOrders: Order[] = Array.isArray(data) ? data : [];
      normalizedOrders.sort(
        (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
      setOrders(normalizedOrders);
    } catch (error) {
      toast({ title: "Erro ao carregar vendas", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOrders();
    fetchStoreSettings();
  }, []);

  const fetchStoreSettings = async () => {
    try {
      const data = await apiGet("/api/settings");
      setStoreSettings({
        storeName: data.storeName || "Gestão Loja",
        address: data.address || "",
        phone: data.phone || "",
        cnpj: data.cnpj || "",
        footerMessage: data.footerMessage || "Obrigado pela preferência!\nVolte sempre!",
        exchangeDays: Number.isFinite(data.exchangeDays) ? data.exchangeDays : 10,
      });
    } catch {
      // keep default settings
    }
  };

  const printReceipt = (order: Order) => {
    if (!order) return;

    const receiptWindow = window.open("", "_blank", "width=420,height=700");
    if (!receiptWindow) {
      toast({ title: "Erro ao abrir janela de impressão", variant: "destructive" });
      return;
    }

    const createdAtDate = new Date(order.createdAt);
    const dateStr = createdAtDate.toLocaleDateString("pt-BR");
    const timeStr = createdAtDate.toLocaleTimeString("pt-BR");
    const exchangeDays = Number.isFinite(storeSettings.exchangeDays) ? Math.max(0, Math.floor(storeSettings.exchangeDays)) : 10;
    const exchangeDeadline = new Date(createdAtDate);
    exchangeDeadline.setDate(exchangeDeadline.getDate() + exchangeDays);
    const exchangeDeadlineStr = exchangeDeadline.toLocaleDateString("pt-BR");

    const subtotal = order.items.reduce((sum, item) => sum + Number(item.totalRevenue || 0), 0);
    const discount = Math.max(0, subtotal - Number(order.totalAmount || 0));

    const paymentLabel: Record<PaymentMethod["method"], string> = {
      DINHEIRO: "Dinheiro",
      DEBITO: "Debito",
      CREDITO: "Credito",
      PIX: "PIX",
    };

    const itemsRows = order.items
      .map((item) => {
        const productName = item.product?.name || "Produto removido";
        const itemName = `${productName}${item.size ? ` (${item.size})` : ""}`;
        const itemTotal = Number(item.totalRevenue || 0);
        return `<tr><td>${item.quantity}x ${itemName}</td><td class="right">${formatCurrency(itemTotal)}</td></tr>`;
      })
      .join("");

    const paymentsRows = (order.payments || [])
      .map((payment) => `<tr><td>${paymentLabel[payment.method] || payment.method}</td><td class="right">${formatCurrency(payment.amount)}</td></tr>`)
      .join("");

    const paymentSection = order.isPaidLater
      ? `<div class="divider"></div><div class="section muted"><div class="meta"><strong>Pagamento:</strong> Fiado</div></div>`
      : (order.payments && order.payments.length > 0
        ? `<div class="divider"></div><table><tbody>${paymentsRows}</tbody></table>`
        : "");

    receiptWindow.document.write(`
      <!DOCTYPE html>
      <html>
      <head>
        <title>Reimpressao de Cupom</title>
        <style>
          * { margin: 0; padding: 0; box-sizing: border-box; }
          html, body { width: 80mm; max-width: 80mm; }
          body {
            font-family: 'Courier New', Courier, monospace;
            font-size: 11px;
            line-height: 1.3;
            font-weight: 600;
            color: #000;
            padding: 0;
            overflow-wrap: anywhere;
            word-break: break-word;
          }
          .receipt { width: 80mm; max-width: 80mm; padding: 2.5mm 2.5mm 3mm; break-after: page; page-break-after: always; }
          .receipt:last-child { break-after: auto; page-break-after: auto; }
          .center { text-align: center; overflow-wrap: anywhere; word-break: break-word; }
          .bold { font-weight: bold; }
          .divider { margin: 8px 0; border-top: 1px dashed #000; }
          .section { margin: 6px 0; }
          .muted { font-size: 11px; }
          .store-name { font-size: 15px; line-height: 1.2; letter-spacing: 0.3px; }
          .line { white-space: pre-wrap; overflow-wrap: anywhere; word-break: break-word; }
          .meta { margin: 2px 0; }
          .meta strong { display: inline-block; min-width: 78px; }
          .policy { margin: 6px 0; text-align: left; }
          .policy-line { display: block; line-height: 1.3; }
          .validity { text-align: center; margin-top: 6px; }
          .footer-note { text-align: center; }
          .title { font-size: 14px; margin-bottom: 4px; }
          table { width: 100%; border-collapse: collapse; }
          td { vertical-align: top; padding: 1px 0; }
          td.right { text-align: right; white-space: nowrap; padding-left: 8px; }
          .totals td { padding-top: 2px; }
          @media print {
            html, body { width: 80mm !important; max-width: 80mm !important; }
            @page { margin: 0; size: 80mm auto; }
            .receipt { break-after: page; page-break-after: always; }
            .receipt:last-child { break-after: auto; page-break-after: auto; }
          }
        </style>
      </head>
      <body>
        <div class="receipt">
          <div class="center">
            <div class="bold store-name line">${storeSettings.storeName.toUpperCase()}</div>
            ${storeSettings.address ? `<div class="line">${storeSettings.address}</div>` : ""}
            ${storeSettings.phone ? `<div class="line">Tel: ${storeSettings.phone}</div>` : ""}
            ${storeSettings.cnpj ? `<div class="line">CNPJ: ${storeSettings.cnpj}</div>` : ""}
          </div>

          <div class="divider"></div>

          <div class="center title bold">CUPOM NAO FISCAL</div>

          <div class="section muted">
            <div class="meta"><strong>Data:</strong> ${dateStr}</div>
            <div class="meta"><strong>Hora:</strong> ${timeStr}</div>
            <div class="meta"><strong>Documento:</strong> #${order.id.slice(-6).toUpperCase()}</div>
            <div class="meta"><strong>Tipo:</strong> Reimpressao</div>
          </div>

          <div class="divider"></div>

          <table>
            <tbody>${itemsRows}</tbody>
          </table>

          <div class="divider"></div>

          <table class="totals">
            <tbody>
              <tr><td>Subtotal</td><td class="right">${formatCurrency(subtotal)}</td></tr>
              ${discount > 0 ? `<tr><td>Desconto</td><td class="right">-${formatCurrency(discount)}</td></tr>` : ""}
              <tr><td><strong>Total</strong></td><td class="right"><strong>${formatCurrency(order.totalAmount)}</strong></td></tr>
            </tbody>
          </table>

          ${paymentSection}

          <div class="divider"></div>
          <div class="center muted">Documento sem valor fiscal</div>
        </div>

        <div class="receipt">
          <div class="center">
            <div class="bold store-name line">${storeSettings.storeName.toUpperCase()}</div>
            ${storeSettings.address ? `<div class="line">${storeSettings.address}</div>` : ""}
            ${storeSettings.phone ? `<div class="line">Tel: ${storeSettings.phone}</div>` : ""}
          </div>

          <div class="divider"></div>

          <div class="section muted">
            <div class="meta"><strong>Data:</strong> ${dateStr}</div>
            <div class="meta"><strong>Hora:</strong> ${timeStr}</div>
            <div class="meta"><strong>Documento:</strong> #${order.id.slice(-6).toUpperCase()}</div>
            <div class="meta"><strong>Tipo:</strong> Reimpressao</div>
          </div>

          <div class="divider"></div>

          <div class="center section">
            <div class="bold title">COMPROVANTE PARA TROCA</div>
            <div class="section policy">
              <span class="policy-line">Trocas em ate ${exchangeDays} dias</span>
              <span class="policy-line">corridos, mediante apresentacao</span>
              <span class="policy-line">deste comprovante.</span>
            </div>
            <div class="validity"><strong>Valido ate:</strong> ${exchangeDeadlineStr}</div>
            <div class="muted footer-note">Produto deve estar sem uso e com etiqueta.</div>
          </div>

          ${storeSettings.footerMessage
            ? `<div class="divider"></div><div class="center section muted">${storeSettings.footerMessage.split("\n").map((line) => `<div class="line">${line}</div>`).join("")}</div>`
            : ""}

          <div class="divider"></div>
          <div class="center muted"><strong>REIMPRESSAO DE CUPOM</strong></div>
        </div>

        <script>
          window.onload = function() {
            window.print();
            window.onafterprint = function() { window.close(); };
          };
        </script>
      </body>
      </html>
    `);

    receiptWindow.document.close();
  };

  const handleFilter = () => {
    fetchOrders();
  };

  const handleClearFilter = () => {
    setStartDate("");
    setEndDate("");
    fetchOrders({ startDate: "", endDate: "" });
  };

  const applyPreset = (preset: "today" | "yesterday" | "this_week" | "this_month" | "last_30" | "last_90" | "all") => {
    const today = new Date();
    const toISO = (d: Date) => d.toISOString().split("T")[0];

    if (preset === "all") {
      setStartDate("");
      setEndDate("");
      fetchOrders({ startDate: "", endDate: "" });
      return;
    }

    if (preset === "today") {
      const t = toISO(today);
      setStartDate(t);
      setEndDate(t);
      fetchOrders({ startDate: t, endDate: t });
      return;
    }

    if (preset === "yesterday") {
      const y = new Date(today);
      y.setDate(today.getDate() - 1);
      const d = toISO(y);
      setStartDate(d);
      setEndDate(d);
      fetchOrders({ startDate: d, endDate: d });
      return;
    }

    if (preset === "this_week") {
      const dayOfWeek = today.getDay();
      const monday = new Date(today);
      monday.setDate(today.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
      const start = toISO(monday);
      const end = toISO(today);
      setStartDate(start);
      setEndDate(end);
      fetchOrders({ startDate: start, endDate: end });
      return;
    }

    if (preset === "this_month") {
      const firstDay = new Date(today.getFullYear(), today.getMonth(), 1);
      const start = toISO(firstDay);
      const end = toISO(today);
      setStartDate(start);
      setEndDate(end);
      fetchOrders({ startDate: start, endDate: end });
      return;
    }

    if (preset === "last_30" || preset === "last_90") {
      const days = preset === "last_30" ? 30 : 90;
      const start = new Date(today);
      start.setDate(today.getDate() - days);
      const startIso = toISO(start);
      const endIso = toISO(today);
      setStartDate(startIso);
      setEndDate(endIso);
      fetchOrders({ startDate: startIso, endDate: endIso });
    }
  };

  const exportCSV = () => {
    const headers = ["ID", "Data", "Total", "Itens"];
    const rows = orders.map((order) => [
      order.id,
      new Date(order.createdAt).toLocaleString("pt-BR"),
      order.totalAmount.toFixed(2),
      order.items.length.toString(),
    ]);

    const csv = [headers, ...rows].map((row) => row.join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `vendas-${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Vendas</h1>
          <p className="text-gray-500">Histórico de vendas realizadas</p>
        </div>
        <Button variant="outline" onClick={exportCSV}>
          <Download className="h-4 w-4 mr-2" />
          Exportar CSV
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Filtros</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex flex-wrap gap-2 mb-4">
            <Button variant="outline" size="sm" onClick={() => applyPreset("today")}>Hoje</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("yesterday")}>Ontem</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("this_week")}>Esta Semana</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("this_month")}>Este Mês</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("last_30")}>Últimos 30 dias</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("last_90")}>Últimos 90 dias</Button>
            <Button variant="outline" size="sm" onClick={() => applyPreset("all")}>Todo Período</Button>
          </div>

          <div className="flex gap-4 items-end">
            <div className="space-y-2">
              <Label>Data Inicial</Label>
              <Input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Data Final</Label>
              <Input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
            <Button onClick={handleFilter}>Filtrar</Button>
            <Button variant="outline" onClick={handleClearFilter}>
              Limpar
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-4 flex-col sm:flex-row">
            <CardTitle className="flex items-center gap-2">
              <ClipboardList className="h-5 w-5" />
              Lista de Vendas
            </CardTitle>
            <div className="text-sm text-gray-600 grid grid-cols-1 gap-1 text-right">
              <div>
                <span className="font-medium">Total vendido:</span> {formatCurrency(periodTotalSold)}
              </div>
              <div>
                <span className="font-medium">Total fiado (pendente):</span> {formatCurrency(periodFiadoOutstanding)}
              </div>
              <div>
                <span className="font-medium">Total recebido:</span> {formatCurrency(periodReceived)}
              </div>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <p className="text-center py-4">Carregando...</p>
          ) : orders.length === 0 ? (
            <p className="text-center py-4 text-gray-500">
              Nenhuma venda encontrada
            </p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Pedido</TableHead>
                  <TableHead>Data</TableHead>
                  <TableHead>Itens</TableHead>
                  <TableHead>Pagamento</TableHead>
                  <TableHead>Cliente</TableHead>
                  <TableHead className="text-right">Total</TableHead>
                  <TableHead className="text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {orders?.map((order) => (
                  <TableRow key={order.id}>
                    <TableCell className="font-medium">
                      #{order.id.slice(-6).toUpperCase()}
                    </TableCell>
                    <TableCell>{formatDate(new Date(order.createdAt))}</TableCell>
                    <TableCell>{order.items.length}</TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        {order.isPaidLater ? (
                          <span className={`text-xs px-2 py-1 rounded ${order.paidAt ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                            {order.paidAt
                              ? 'Fiado (Pago)'
                              : `Fiado (${formatCurrency(order.remainingAmount ?? order.totalAmount)})`}
                          </span>
                        ) : (
                          <>
                            {order.payments?.map((p, i) => (
                              <span key={i} className="text-xs bg-gray-100 px-2 py-1 rounded">
                                {p.method === "DINHEIRO" && "Dinheiro"}
                                {p.method === "DEBITO" && "Débito"}
                                {p.method === "CREDITO" && "Crédito"}
                                {p.method === "PIX" && "PIX"}
                              </span>
                            ))}
                            {(!order.payments || order.payments.length === 0) && (
                              <span className="text-xs text-gray-400">-</span>
                            )}
                          </>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      {order.clientName ? (
                        <span className="text-sm text-blue-600">{order.clientName}</span>
                      ) : (
                        <span className="text-xs text-gray-400">-</span>
                      )}
                    </TableCell>
                    <TableCell className="text-right font-bold">
                      {formatCurrency(order.totalAmount)}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-1">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => printReceipt(order)}
                          title="Reimprimir cupom"
                        >
                          <Printer className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setSelectedOrder(order)}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <Dialog open={!!selectedOrder} onOpenChange={() => setSelectedOrder(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>
              Detalhes do Pedido #{selectedOrder?.id.slice(-6).toUpperCase()}
            </DialogTitle>
          </DialogHeader>
          {selectedOrder && (
            <div className="space-y-4">
              <div className="flex justify-between text-sm text-gray-600">
                <span>Data: {formatDate(new Date(selectedOrder.createdAt))}</span>
                <span className="font-bold text-lg">
                  Total: {formatCurrency(selectedOrder.totalAmount)}
                </span>
              </div>

              {selectedOrder.isPaidLater && (
                <div className={`p-3 rounded-lg ${selectedOrder.paidAt ? 'bg-green-50 border border-green-200' : 'bg-orange-50 border border-orange-200'}`}>
                  <div className="flex justify-between items-center">
                    <div>
                      <p className={`font-medium ${selectedOrder.paidAt ? 'text-green-700' : 'text-orange-700'}`}>
                        {selectedOrder.paidAt ? 'Venda Fiado (Pago)' : 'Venda Fiado (Pendente)'}
                      </p>
                      <p className="text-sm text-gray-600">Cliente: {selectedOrder.clientName}</p>
                      <p className="text-xs text-gray-600">
                        Pago: {formatCurrency(selectedOrder.amountPaid || 0)} | Restante: {formatCurrency(selectedOrder.remainingAmount ?? selectedOrder.totalAmount)}
                      </p>
                    </div>
                    {selectedOrder.paidAt && (
                      <p className="text-xs text-green-600">
                        Pago em: {formatDate(new Date(selectedOrder.paidAt))}
                      </p>
                    )}
                  </div>
                </div>
              )}

              {selectedOrder.isPaidLater && selectedOrder.paymentHistory && selectedOrder.paymentHistory.length > 0 && (
                <div>
                  <h4 className="font-semibold mb-2">Histórico de Pagamentos</h4>
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Data</TableHead>
                        <TableHead>Forma</TableHead>
                        <TableHead className="text-right">Valor</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {selectedOrder.paymentHistory.map((p) => (
                        <TableRow key={p.id}>
                          <TableCell>{formatDate(new Date(p.createdAt))}</TableCell>
                          <TableCell>
                            {p.method === "DINHEIRO" && "Dinheiro"}
                            {p.method === "DEBITO" && "Débito"}
                            {p.method === "CREDITO" && "Crédito"}
                            {p.method === "PIX" && "PIX"}
                          </TableCell>
                          <TableCell className="text-right">{formatCurrency(p.amount)}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}

              {selectedOrder.payments && selectedOrder.payments.length > 0 && (
                <div>
                  <h4 className="font-semibold mb-2">Formas de Pagamento</h4>
                  <div className="grid grid-cols-2 gap-2">
                    {selectedOrder.payments.map((payment, index) => (
                      <div key={index} className="flex items-center gap-2 p-2 bg-gray-50 rounded-lg">
                        {payment.method === "DINHEIRO" && <Banknote className="h-4 w-4 text-green-600" />}
                        {payment.method === "DEBITO" && <CreditCard className="h-4 w-4 text-blue-600" />}
                        {payment.method === "CREDITO" && <CreditCard className="h-4 w-4 text-purple-600" />}
                        {payment.method === "PIX" && <Smartphone className="h-4 w-4 text-teal-600" />}
                        <span className="text-sm">
                          {payment.method === "DINHEIRO" && "Dinheiro"}
                          {payment.method === "DEBITO" && "Débito"}
                          {payment.method === "CREDITO" && "Crédito"}
                          {payment.method === "PIX" && "PIX"}
                        </span>
                        <span className="ml-auto font-medium">{formatCurrency(payment.amount)}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div>
                <h4 className="font-semibold mb-2">Itens</h4>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Produto</TableHead>
                      <TableHead className="text-right">Qtd</TableHead>
                      <TableHead className="text-right">Preço</TableHead>
                      <TableHead className="text-right">Total</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {selectedOrder.items.map((item) => (
                      <TableRow key={item.id}>
                        <TableCell>{item.product?.name || "Produto removido"}</TableCell>
                        <TableCell className="text-right">
                          {item.quantity}
                        </TableCell>
                        <TableCell className="text-right">
                          {formatCurrency(item.unitPrice)}
                        </TableCell>
                        <TableCell className="text-right">
                          {formatCurrency(item.totalRevenue)}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>

              <div className="flex justify-end">
                <Button variant="outline" onClick={() => printReceipt(selectedOrder)}>
                  <Printer className="h-4 w-4 mr-2" />
                  Reimprimir cupom
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { apiGet, apiPut, apiPost } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/components/ui/use-toast";
import { Save, Store, Receipt, Percent, Search, X } from "lucide-react";
import { Textarea } from "@/components/ui/textarea";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

interface Product {
  id: string;
  name: string;
  sku: string;
  salePrice: number;
  stock: number;
}

interface ProductDiscount {
  productId: string;
  discountPercent: number;
}

interface ProductDiscountSelectorProps {
  productDiscounts: ProductDiscount[];
  onChange: (productDiscounts: ProductDiscount[]) => void;
}

function ProductDiscountSelector({ productDiscounts, onChange }: ProductDiscountSelectorProps) {
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const data = await apiGet("/api/products");
      setProducts(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error fetching products:", error);
    } finally {
      setLoading(false);
    }
  };

  const filteredProducts = products.filter((product) =>
    product.name.toLowerCase().includes(search.toLowerCase()) ||
    product.sku.toLowerCase().includes(search.toLowerCase())
  );

  const addProductDiscount = (productId: string) => {
    const existing = productDiscounts.find(pd => pd.productId === productId);
    if (!existing) {
      onChange([...productDiscounts, { productId, discountPercent: 0 }]);
    }
  };

  const updateProductDiscount = (productId: string, discountPercent: number) => {
    onChange(
      productDiscounts.map(pd =>
        pd.productId === productId ? { ...pd, discountPercent } : pd
      )
    );
  };

  const removeProductDiscount = (productId: string) => {
    onChange(productDiscounts.filter(pd => pd.productId !== productId));
  };

  const getProduct = (productId: string) => products.find(p => p.id === productId);

  return (
    <div className="space-y-4">
      <div className="space-y-2">
        <Label>Adicionar Produto</Label>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          <Input
            placeholder="Buscar por nome ou SKU..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-10"
          />
        </div>
        {search && !loading && (
          <div className="border rounded-lg max-h-40 overflow-y-auto">
            {filteredProducts.length === 0 ? (
              <p className="text-center py-2 text-sm text-gray-500">Nenhum produto encontrado</p>
            ) : (
              filteredProducts.map((product) => {
                const hasDiscount = productDiscounts.some(pd => pd.productId === product.id);
                return (
                  <div
                    key={product.id}
                    className={`p-2 hover:bg-gray-50 cursor-pointer flex justify-between items-center ${
                      hasDiscount ? "bg-gray-50" : ""
                    }`}
                    onClick={() => !hasDiscount && addProductDiscount(product.id)}
                  >
                    <div>
                      <p className="font-medium">{product.name}</p>
                      <p className="text-sm text-gray-500">{product.sku}</p>
                    </div>
                    {hasDiscount ? (
                      <span className="text-xs text-green-600">Já adicionado</span>
                    ) : (
                      <Button size="sm" variant="outline">Adicionar</Button>
                    )}
                  </div>
                );
              })
            )}
          </div>
        )}
      </div>

      {productDiscounts.length > 0 && (
        <div className="space-y-2">
          <Label>Produtos com Desconto</Label>
          <div className="space-y-2">
            {productDiscounts.map((pd) => {
              const product = getProduct(pd.productId);
              return (
                <div key={pd.productId} className="flex items-center gap-2 p-2 border rounded">
                  <div className="flex-1">
                    <p className="font-medium">{product?.name || "Produto não encontrado"}</p>
                    <p className="text-sm text-gray-500">{product?.sku}</p>
                  </div>
                  <div className="flex items-center gap-1">
                    <Input
                      type="number"
                      min="0"
                      max="100"
                      step="0.5"
                      value={pd.discountPercent}
                      onChange={(e) => updateProductDiscount(pd.productId, parseFloat(e.target.value) || 0)}
                      className="w-16 text-right"
                    />
                    <span className="text-gray-500 text-sm">%</span>
                  </div>
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => removeProductDiscount(pd.productId)}
                  >
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

interface DiscountSettings {
  pixDiscountEnabled: boolean;
  pixDiscountPercent: number;
  fixedDiscountEnabled: boolean;
  fixedDiscountPercent: number;
  progressiveDiscountEnabled: boolean;
  progressiveDiscount1Item: number;
  progressiveDiscount2Items: number;
  progressiveDiscount3PlusItems: number;
  productDiscountsEnabled: boolean;
  productDiscounts: ProductDiscount[];
}

interface StoreSettings {
  storeName: string;
  address: string;
  phone: string;
  cnpj: string;
  footerMessage: string;
  exchangeDays: number;
  discounts: DiscountSettings;
}

export default function SettingsPage() {
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [billSaving, setBillSaving] = useState(false);
  const [settings, setSettings] = useState<StoreSettings>({
    storeName: "",
    address: "",
    phone: "",
    cnpj: "",
    footerMessage: "",
    exchangeDays: 10,
    discounts: {
      pixDiscountEnabled: false,
      pixDiscountPercent: 5,
      fixedDiscountEnabled: false,
      fixedDiscountPercent: 0,
      progressiveDiscountEnabled: false,
      progressiveDiscount1Item: 0,
      progressiveDiscount2Items: 0,
      progressiveDiscount3PlusItems: 0,
      productDiscountsEnabled: false,
      productDiscounts: [],
    },
  });

  const [billKind, setBillKind] = useState<"ONE_TIME" | "FIXED" | "INSTALLMENTS">("ONE_TIME");
  const [billName, setBillName] = useState("");
  const [billAmount, setBillAmount] = useState<string>("");
  const [billDueDate, setBillDueDate] = useState<string>(new Date().toISOString().slice(0, 10));
  const [billDayOfMonth, setBillDayOfMonth] = useState<string>("5");
  const [billMonthsAhead, setBillMonthsAhead] = useState<string>("12");
  const [billFirstDueDate, setBillFirstDueDate] = useState<string>(new Date().toISOString().slice(0, 10));
  const [billInstallmentsCount, setBillInstallmentsCount] = useState<string>("3");

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      const data = await apiGet("/api/settings");
      setSettings({
        storeName: data.storeName || "",
        address: data.address || "",
        phone: data.phone || "",
        cnpj: data.cnpj || "",
        footerMessage: data.footerMessage || "",
        exchangeDays: Number.isFinite(data.exchangeDays) ? data.exchangeDays : 10,
        discounts: {
          pixDiscountEnabled: data.discounts?.pixDiscountEnabled ?? false,
          pixDiscountPercent: data.discounts?.pixDiscountPercent ?? 5,
          fixedDiscountEnabled: data.discounts?.fixedDiscountEnabled ?? false,
          fixedDiscountPercent: data.discounts?.fixedDiscountPercent ?? 0,
          progressiveDiscountEnabled: data.discounts?.progressiveDiscountEnabled ?? false,
          progressiveDiscount1Item: data.discounts?.progressiveDiscount1Item ?? 0,
          progressiveDiscount2Items: data.discounts?.progressiveDiscount2Items ?? 0,
          progressiveDiscount3PlusItems: data.discounts?.progressiveDiscount3PlusItems ?? 0,
          productDiscountsEnabled: data.discounts?.productDiscountsEnabled ?? false,
          productDiscounts: data.discounts?.productDiscounts ?? [],
        },
      });
    } catch (error) {
      toast({ title: "Erro ao carregar configurações", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const previewExchangeDeadline = new Date();
  previewExchangeDeadline.setDate(previewExchangeDeadline.getDate() + Math.max(0, Math.floor(settings.exchangeDays || 0)));
  const previewExchangeDeadlineStr = previewExchangeDeadline.toLocaleDateString("pt-BR");

  const handleCreateBill = async () => {
    const parsed = parseFloat(billAmount);
    if (!billName.trim()) {
      toast({ title: "Informe o nome da conta", variant: "destructive" });
      return;
    }
    if (!Number.isFinite(parsed) || parsed <= 0) {
      toast({ title: "Informe um valor válido", variant: "destructive" });
      return;
    }

    setBillSaving(true);
    try {
      if (billKind === "ONE_TIME") {
        await apiPost("/api/bills", {
          kind: "ONE_TIME",
          name: billName.trim(),
          amount: parsed,
          dueDate: billDueDate,
        });
      }

      if (billKind === "FIXED") {
        await apiPost("/api/bills", {
          kind: "FIXED",
          name: billName.trim(),
          amount: parsed,
          dayOfMonth: parseInt(billDayOfMonth, 10),
          monthsAhead: parseInt(billMonthsAhead, 10),
          startMonth: new Date().toISOString().slice(0, 7),
        });
      }

      if (billKind === "INSTALLMENTS") {
        await apiPost("/api/bills", {
          kind: "INSTALLMENTS",
          name: billName.trim(),
          amount: parsed,
          firstDueDate: billFirstDueDate,
          installmentsCount: parseInt(billInstallmentsCount, 10),
          intervalMonths: 1,
        });
      }

      toast({ title: "Conta(s) criada(s)" });
      setBillName("");
      setBillAmount("");
    } catch (error) {
      toast({
        title: "Erro ao criar conta",
        description: error instanceof Error ? error.message : "Erro desconhecido",
        variant: "destructive",
      });
    } finally {
      setBillSaving(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await apiPut("/api/settings", settings);
      toast({ title: "Configurações salvas com sucesso!" });
    } catch (error) {
      toast({ title: "Erro ao salvar configurações", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <p>Carregando configurações...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-[#2A5473]">Configurações</h1>
        <p className="text-gray-500">Personalize as informações da sua loja</p>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Store className="h-5 w-5 text-[#355444]" />
              Dados da Loja
            </CardTitle>
            <CardDescription>
              Informações que aparecem no cabeçalho do cupom
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="storeName">Nome da Loja</Label>
              <Input
                id="storeName"
                value={settings.storeName}
                onChange={(e) => setSettings({ ...settings, storeName: e.target.value })}
                placeholder="Minha Loja"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="address">Endereço</Label>
              <Input
                id="address"
                value={settings.address}
                onChange={(e) => setSettings({ ...settings, address: e.target.value })}
                placeholder="Rua Exemplo, 123 - Centro"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="phone">Telefone</Label>
              <Input
                id="phone"
                value={settings.phone}
                onChange={(e) => setSettings({ ...settings, phone: e.target.value })}
                placeholder="(11) 99999-9999"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="cnpj">CNPJ</Label>
              <Input
                id="cnpj"
                value={settings.cnpj}
                onChange={(e) => setSettings({ ...settings, cnpj: e.target.value })}
                placeholder="00.000.000/0001-00"
              />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Receipt className="h-5 w-5 text-[#355444]" />
              Cupom Fiscal
            </CardTitle>
            <CardDescription>
              Personalize a mensagem do rodapé do cupom
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="footerMessage">Mensagem do Rodapé</Label>
              <Textarea
                id="footerMessage"
                value={settings.footerMessage}
                onChange={(e) => setSettings({ ...settings, footerMessage: e.target.value })}
                placeholder="Obrigado pela preferência!&#10;Volte sempre!"
                rows={4}
              />
              <p className="text-xs text-gray-500">
                Use Enter para quebrar linhas
              </p>
            </div>

            <div className="space-y-2">
              <Label htmlFor="exchangeDays">Prazo de troca (dias corridos)</Label>
              <Input
                id="exchangeDays"
                type="number"
                min="0"
                max="365"
                value={settings.exchangeDays}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    exchangeDays: Math.max(0, Math.floor(Number(e.target.value) || 0)),
                  })
                }
              />
              <p className="text-xs text-gray-500">
                Esse prazo sera usado no comprovante para troca impresso no PDV.
              </p>
            </div>

            <div className="p-4 bg-gray-100 rounded-lg">
              <p className="text-xs text-gray-500 mb-2">Prévia do Cupom:</p>
              <div className="font-mono text-xs bg-white p-3 rounded border">
                <div className="text-center border-b border-dashed pb-2 mb-2">
                  <p className="font-bold">{settings.storeName || "NOME DA LOJA"}</p>
                  {settings.address && <p>{settings.address}</p>}
                  {settings.phone && <p>Tel: {settings.phone}</p>}
                  {settings.cnpj && <p>CNPJ: {settings.cnpj}</p>}
                </div>
                <p className="text-center text-gray-500">... itens da venda ...</p>
                <div className="text-center border-t border-dashed pt-2 mt-2">
                  <p className="font-semibold">Comprovante para troca</p>
                  <p>Trocas em ate {Math.max(0, Math.floor(settings.exchangeDays || 0))} dias corridos</p>
                  <p>Valido ate: {previewExchangeDeadlineStr}</p>
                </div>
                <div className="text-center border-t border-dashed pt-2 mt-2">
                  {settings.footerMessage.split('\n').map((line, i) => (
                    <p key={i}>{line}</p>
                  ))}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Percent className="h-5 w-5 text-[#355444]" />
            Descontos Automáticos
          </CardTitle>
          <CardDescription>
            Configure descontos que serão aplicados automaticamente nas vendas
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-4 p-4 border rounded-lg">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-base font-medium">Desconto PIX</Label>
                <p className="text-sm text-gray-500">Aplica desconto em pagamentos via PIX</p>
              </div>
              <Checkbox
                checked={settings.discounts.pixDiscountEnabled}
                onCheckedChange={(checked) =>
                  setSettings({
                    ...settings,
                    discounts: { ...settings.discounts, pixDiscountEnabled: checked === true },
                  })
                }
              />
            </div>
            {settings.discounts.pixDiscountEnabled && (
              <div className="flex items-center gap-2 pl-4 border-l-2 border-[#355444]">
                <Label htmlFor="pixPercent" className="whitespace-nowrap">Porcentagem:</Label>
                <Input
                  id="pixPercent"
                  type="number"
                  min="0"
                  max="100"
                  step="0.5"
                  value={settings.discounts.pixDiscountPercent}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      discounts: { ...settings.discounts, pixDiscountPercent: parseFloat(e.target.value) || 0 },
                    })
                  }
                  className="w-24"
                />
                <span className="text-gray-500">%</span>
              </div>
            )}
          </div>

          <div className="space-y-4 p-4 border rounded-lg">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-base font-medium">Desconto Fixo</Label>
                <p className="text-sm text-gray-500">Aplica um percentual fixo de desconto em todas as vendas</p>
              </div>
              <Checkbox
                checked={settings.discounts.fixedDiscountEnabled}
                onCheckedChange={(checked) =>
                  setSettings({
                    ...settings,
                    discounts: { ...settings.discounts, fixedDiscountEnabled: checked === true },
                  })
                }
              />
            </div>
            {settings.discounts.fixedDiscountEnabled && (
              <div className="flex items-center gap-2 pl-4 border-l-2 border-[#355444]">
                <Label htmlFor="fixedPercent" className="whitespace-nowrap">Porcentagem:</Label>
                <Input
                  id="fixedPercent"
                  type="number"
                  min="0"
                  max="100"
                  step="0.5"
                  value={settings.discounts.fixedDiscountPercent}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      discounts: { ...settings.discounts, fixedDiscountPercent: parseFloat(e.target.value) || 0 },
                    })
                  }
                  className="w-24"
                />
                <span className="text-gray-500">%</span>
              </div>
            )}
          </div>

          <div className="space-y-4 p-4 border rounded-lg">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-base font-medium">Desconto Progressivo</Label>
                <p className="text-sm text-gray-500">Desconto baseado na quantidade de itens</p>
              </div>
              <Checkbox
                checked={settings.discounts.progressiveDiscountEnabled}
                onCheckedChange={(checked) =>
                  setSettings({
                    ...settings,
                    discounts: { ...settings.discounts, progressiveDiscountEnabled: checked === true },
                  })
                }
              />
            </div>
            {settings.discounts.progressiveDiscountEnabled && (
              <div className="space-y-3 pl-4 border-l-2 border-[#355444]">
                <div className="flex items-center gap-2">
                  <Label className="w-24 whitespace-nowrap">1 item:</Label>
                  <Input
                    type="number"
                    min="0"
                    max="100"
                    step="0.5"
                    value={settings.discounts.progressiveDiscount1Item}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        discounts: { ...settings.discounts, progressiveDiscount1Item: parseFloat(e.target.value) || 0 },
                      })
                    }
                    className="w-20"
                  />
                  <span className="text-gray-500">%</span>
                </div>
                <div className="flex items-center gap-2">
                  <Label className="w-24 whitespace-nowrap">2 itens:</Label>
                  <Input
                    type="number"
                    min="0"
                    max="100"
                    step="0.5"
                    value={settings.discounts.progressiveDiscount2Items}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        discounts: { ...settings.discounts, progressiveDiscount2Items: parseFloat(e.target.value) || 0 },
                      })
                    }
                    className="w-20"
                  />
                  <span className="text-gray-500">%</span>
                </div>
                <div className="flex items-center gap-2">
                  <Label className="w-24 whitespace-nowrap">3+ itens:</Label>
                  <Input
                    type="number"
                    min="0"
                    max="100"
                    step="0.5"
                    value={settings.discounts.progressiveDiscount3PlusItems}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        discounts: { ...settings.discounts, progressiveDiscount3PlusItems: parseFloat(e.target.value) || 0 },
                      })
                    }
                    className="w-20"
                  />
                  <span className="text-gray-500">%</span>
                </div>
              </div>
            )}
          </div>

          <div className="space-y-4 p-4 border rounded-lg">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-base font-medium">Descontos por Produto</Label>
                <p className="text-sm text-gray-500">Configure descontos específicos para produtos selecionados</p>
              </div>
              <Checkbox
                checked={settings.discounts.productDiscountsEnabled}
                onCheckedChange={(checked) =>
                  setSettings({
                    ...settings,
                    discounts: { ...settings.discounts, productDiscountsEnabled: checked === true },
                  })
                }
              />
            </div>
            {settings.discounts.productDiscountsEnabled && (
              <ProductDiscountSelector 
                productDiscounts={settings.discounts.productDiscounts}
                onChange={(productDiscounts) =>
                  setSettings({
                    ...settings,
                    discounts: { ...settings.discounts, productDiscounts },
                  })
                }
              />
            )}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Receipt className="h-5 w-5 text-[#355444]" />
            Contas da Loja
          </CardTitle>
          <CardDescription>
            Cadastre contas fixas, avulsas e parceladas
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 md:grid-cols-4">
            <div className="space-y-2 md:col-span-2">
              <Label>Nome</Label>
              <Input value={billName} onChange={(e) => setBillName(e.target.value)} placeholder="Ex: Aluguel" />
            </div>
            <div className="space-y-2">
              <Label>Valor</Label>
              <Input value={billAmount} onChange={(e) => setBillAmount(e.target.value)} type="number" step="0.01" />
            </div>
            <div className="space-y-2">
              <Label>Tipo</Label>
              <select
                className="w-full p-2 border rounded-md"
                value={billKind}
                onChange={(e) => setBillKind(e.target.value as typeof billKind)}
              >
                <option value="ONE_TIME">Avulsa</option>
                <option value="FIXED">Fixa</option>
                <option value="INSTALLMENTS">Parcelada</option>
              </select>
            </div>
          </div>

          {billKind === "ONE_TIME" && (
            <div className="space-y-2">
              <Label>Vencimento</Label>
              <Input type="date" value={billDueDate} onChange={(e) => setBillDueDate(e.target.value)} />
            </div>
          )}

          {billKind === "FIXED" && (
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label>Dia do vencimento</Label>
                <Input
                  type="number"
                  min="1"
                  max="31"
                  value={billDayOfMonth}
                  onChange={(e) => setBillDayOfMonth(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Meses à frente</Label>
                <Input
                  type="number"
                  min="1"
                  max="36"
                  value={billMonthsAhead}
                  onChange={(e) => setBillMonthsAhead(e.target.value)}
                />
              </div>
            </div>
          )}

          {billKind === "INSTALLMENTS" && (
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label>1º vencimento</Label>
                <Input
                  type="date"
                  value={billFirstDueDate}
                  onChange={(e) => setBillFirstDueDate(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Nº parcelas</Label>
                <Input
                  type="number"
                  min="1"
                  max="60"
                  value={billInstallmentsCount}
                  onChange={(e) => setBillInstallmentsCount(e.target.value)}
                />
              </div>
            </div>
          )}

          <div className="flex justify-end">
            <Button onClick={handleCreateBill} disabled={billSaving}>
              {billSaving ? "Salvando..." : "Adicionar Conta"}
            </Button>
          </div>
        </CardContent>
      </Card>

      <div className="flex justify-end">
        <Button onClick={handleSave} disabled={saving} className="bg-[#2A5473] hover:bg-[#2A5473]/90">
          <Save className="h-4 w-4 mr-2" />
          {saving ? "Salvando..." : "Salvar Configurações"}
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/contexts/auth-context";
import { apiDelete, apiGet, apiPost, apiPut } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { useToast } from "@/components/ui/use-toast";
import { Plus, Pencil, Trash2, Truck } from "lucide-react";

type PaymentMethod = "DINHEIRO" | "DEBITO" | "CREDITO" | "PIX" | "FIADO";

type Supplier = {
  id: string;
  name: string;
  instagram?: string;
  whatsapp?: string;
  website?: string;
  observations?: string;
  acceptedPaymentMethods: PaymentMethod[];
};

const ALL_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "DINHEIRO", label: "Dinheiro" },
  { value: "DEBITO", label: "Débito" },
  { value: "CREDITO", label: "Crédito" },
  { value: "PIX", label: "PIX" },
  { value: "FIADO", label: "Fiado" },
];

export default function SuppliersPage() {
  const { userData } = useAuth();
  const { toast } = useToast();

  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingSupplier, setEditingSupplier] = useState<Supplier | null>(null);

  const [formData, setFormData] = useState({
    name: "",
    instagram: "",
    whatsapp: "",
    website: "",
    observations: "",
    acceptedPaymentMethods: [] as PaymentMethod[],
  });

  const fetchSuppliers = async () => {
    try {
      const data = await apiGet("/api/suppliers");
      setSuppliers(Array.isArray(data) ? data : []);
    } catch (error) {
      toast({ title: "Erro ao carregar fornecedores", variant: "destructive" });
      setSuppliers([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSuppliers();
  }, []);

  const resetForm = () => {
    setEditingSupplier(null);
    setFormData({
      name: "",
      instagram: "",
      whatsapp: "",
      website: "",
      observations: "",
      acceptedPaymentMethods: [],
    });
  };

  const openNewDialog = () => {
    resetForm();
    setDialogOpen(true);
  };

  const handleEdit = (supplier: Supplier) => {
    setEditingSupplier(supplier);
    setFormData({
      name: supplier.name || "",
      instagram: supplier.instagram || "",
      whatsapp: supplier.whatsapp || "",
      website: supplier.website || "",
      observations: supplier.observations || "",
      acceptedPaymentMethods: supplier.acceptedPaymentMethods || [],
    });
    setDialogOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Tem certeza que deseja excluir este fornecedor?")) return;

    try {
      await apiDelete(`/api/suppliers/${id}`);
      toast({ title: "Fornecedor excluído!" });
      fetchSuppliers();
    } catch (error) {
      toast({ title: "Erro ao excluir fornecedor", variant: "destructive" });
    }
  };

  const toggleMethod = (m: PaymentMethod) => {
    setFormData((prev) => {
      const has = prev.acceptedPaymentMethods.includes(m);
      return {
        ...prev,
        acceptedPaymentMethods: has
          ? prev.acceptedPaymentMethods.filter((x) => x !== m)
          : [...prev.acceptedPaymentMethods, m],
      };
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      toast({ title: "Informe o nome", variant: "destructive" });
      return;
    }

    try {
      const payload = {
        name: formData.name.trim(),
        instagram: formData.instagram.trim(),
        whatsapp: formData.whatsapp.trim(),
        website: formData.website.trim(),
        observations: formData.observations.trim(),
        acceptedPaymentMethods: formData.acceptedPaymentMethods,
      };

      if (editingSupplier) {
        await apiPut(`/api/suppliers/${editingSupplier.id}`, payload);
        toast({ title: "Fornecedor atualizado!" });
      } else {
        await apiPost("/api/suppliers", payload);
        toast({ title: "Fornecedor criado!" });
      }

      setDialogOpen(false);
      resetForm();
      fetchSuppliers();
    } catch (error) {
